import{_ as t,o,c as a,ag as s}from"./chunks/framework.eQLvDOR_.js";const g=JSON.parse(`{"title":"How to 10x your Claude Skills (using Karpathy's autoresearch method)","description":"","frontmatter":{"title":"How to 10x your Claude Skills (using Karpathy's autoresearch method)","source":"https://x.com/itsolelehmann/article/2033919415771713715","category":"[Claude_Code_Skills]","clipped_at":"2026-04-04","tags":["claude-code-skills"],"status":"distilled","compiled":true},"headers":[],"relativePath":"library/Claude_Code_Skills/Claude_Code_Skills - How-to-10x-your-Claude-Skills-(using-Karpathys-autoresearch-method).md","filePath":"library/Claude_Code_Skills/Claude_Code_Skills - How-to-10x-your-Claude-Skills-(using-Karpathys-autoresearch-method).md","lastUpdated":null}`),i={name:"library/Claude_Code_Skills/Claude_Code_Skills - How-to-10x-your-Claude-Skills-(using-Karpathys-autoresearch-method).md"};function r(n,e,l,h,u,p){return o(),a("div",null,[...e[0]||(e[0]=[s('<p>Your Claude skills probably fail 30% of the time and you don&#39;t even notice.</p><p>I built a method that auto-improves any skill on autopilot, and in this article I&#39;m going to show you <strong>exactly</strong> how to run it yourself.</p><p>You kick it off, and the agent tests and refines the skill over and over without you touching anything.</p><p>My landing page copy skill went from passing its quality checks 56% of the time to 92%. With <strong>zero</strong> manual work at all.</p><p>The agent just kept testing and tightening the prompt on its own.</p><p>Here&#39;s the method and the exact skill I built so you can run it on your own stuff:</p><p>P.S. If you want more AI workflows like this one delivered to your inbox every week, join 34k readers getting them free: <a href="http://aisolo.beehiiv.com/subscribe" target="_blank" rel="noreferrer">aisolo.beehiiv.com/subscribe</a></p><h2 id="where-this-comes-from" tabindex="-1">Where this comes from <a class="header-anchor" href="#where-this-comes-from" aria-label="Permalink to &quot;Where this comes from&quot;">​</a></h2><p>Andrej Karpathy (co-founder of OpenAI, former head of AI at Tesla, guy who coined “vibe coding”) released a method called <strong>autoresearch.</strong></p><p>The idea is simple: instead of you manually improving something, you let an AI agent do it for you in a loop.</p><p><img src="https://pbs.twimg.com/media/HDnlDjwWkAANoH8?format=jpg&amp;name=large" alt="Image"></p><p>It tries a small change. Checks if the result got better. Keeps it if it did, throws it out if it didn&#39;t.</p><p>Then it does it again. And again.</p><p>He used it for machine learning code. But the method works on <strong>anything you can measure and improve.</strong></p><p>Including the skills you&#39;ve built in Claude.</p><p>I took his method and turned it into a skill that works in both Claude Code and Cowork. I just run it on any other skill in my setup.</p><p>I say &quot;run autoresearch on my landing page skill&quot; and it handles the whole thing.</p><h2 id="how-one-loop-auto-improves-your-skills" tabindex="-1">How one loop auto-improves your skills <a class="header-anchor" href="#how-one-loop-auto-improves-your-skills" aria-label="Permalink to &quot;How one loop auto-improves your skills&quot;">​</a></h2><p>Think of it like this.</p><p>You have a recipe that turns out great 7 out of 10 times. The other 3 times, something&#39;s off. Maybe the sauce is bland, maybe the seasoning is wrong.</p><p>Instead of rewriting the whole recipe from scratch, you <strong>change one ingredient.</strong> You cook it 10 times with that change.</p><ul><li>Did it get better? Keep the change.</li><li>Did it get worse? Put the old ingredient back.</li></ul><p>Then you change the next thing. Cook 10 more times. Better or worse? Keep or revert.</p><p>After 50 rounds of this, your recipe works <strong>9.5 out of 10 times.</strong></p><p>That&#39;s exactly what autoresearch does to your skills.</p><ul><li>The &quot;recipe&quot; is your skill prompt.</li><li>The &quot;cooking&quot; is running the skill.</li><li>The &quot;tasting&quot; is scoring the output.</li></ul><p>The only thing you need to provide is the scoring criteria.</p><h2 id="the-checklist-that-tells-the-agent-exactly-what-good-means" tabindex="-1">The checklist that tells the agent exactly what &#39;good&#39; means <a class="header-anchor" href="#the-checklist-that-tells-the-agent-exactly-what-good-means" aria-label="Permalink to &quot;The checklist that tells the agent exactly what &#39;good&#39; means&quot;">​</a></h2><p>You give the agent a simple checklist of what &quot;good&quot; looks like. <strong>That&#39;s your only job in this whole process.</strong></p><p>You do it with a simple checklist of yes/no questions.</p><p>Each question checks one specific thing about the output. Pass or fail. That&#39;s it.</p><p>The agent uses this checklist to score every output, and those scores tell it whether its changes are helping or hurting.</p><p>Think of it like a teacher grading a paper with a checklist.</p><p>But instead of &quot;rate the writing quality 1-10&quot; (which is vague and different every time), each item on the checklist is a <strong>clear yes or no:</strong></p><ul><li>Did the student include a thesis statement? Yes or no.</li><li>Is every source cited? Yes or no.</li><li>Is it under 5 pages? Yes or no.</li></ul><p>You can grade 100 papers with that checklist and get <strong>consistent results every time.</strong></p><p>Same idea here. For a landing page copy skill, your checklist might look like:</p><ul><li>&quot;Does the headline include a specific number or result?&quot; (catches vague headlines like &quot;Grow Your Business&quot;)</li><li>&quot;Is the copy free of buzzwords like &#39;revolutionary,&#39; &#39;synergy,&#39; &#39;cutting-edge,&#39; &#39;next-level&#39;?&quot;</li><li>&quot;Does the CTA use a specific verb phrase?&quot; (catches weak CTAs like &quot;Learn More&quot; or &quot;Click Here&quot;)</li><li>&quot;Does the first line call out a specific pain point?&quot; (catches generic openers like &quot;In today&#39;s fast-paced world...&quot;)</li><li>&quot;Is the total copy under 150 words?&quot; (catches bloated pages that lose the reader)</li></ul><p>You don&#39;t need to figure these out on your own. When you start the autoresearch, the agent walks you through it.</p><p>It asks what good looks like, helps you turn your vibes into specific yes/no questions, and even offers to pull from existing style guides if you have them.</p><p><strong>3-6 questions is the sweet spot.</strong> More than that and the skill starts gaming the checklist (like a student who memorizes the answers without understanding the material).</p><h2 id="here-s-how-to-run-it" tabindex="-1">Here&#39;s how to run it <a class="header-anchor" href="#here-s-how-to-run-it" aria-label="Permalink to &quot;Here&#39;s how to run it&quot;">​</a></h2><p><strong>Step 1: Download the skill.</strong> Grab it <a href="https://www.dropbox.com/scl/fi/57v11vtj9gzqz10ybv7or/autoresearch.zip?rlkey=f0zbieol7beeykn04erun79ot&amp;dl=1" target="_blank" rel="noreferrer">here</a>. Drop it into your skills folder in Claude Code or Cowork.</p><p><strong>Step 2: Pick a skill to improve.</strong> Say &quot;run autoresearch on my [skill name] skill.&quot; Pick the one that annoys you most. The one where you get a great output half the time and garbage the other half.</p><p><strong>Step 3: The agent asks you 3 things.</strong> Which skill to optimize. What test inputs to use (like &quot;write landing page copy for an AI productivity tool&quot;). And what your checklist questions are.</p><p><strong>Step 4: It runs your skill and shows you your starting score.</strong> This is the baseline. My landing page skill started at <strong>56%.</strong> Vague headlines, buzzword soup, weak CTAs. More than half the checks were failing.</p><p><strong>Step 5: It opens a live dashboard in your browser.</strong> Score chart going up over time. Pass/fail breakdown for each checklist question. A log of every change it tried. Auto-refreshes every 10 seconds.</p><p><strong>Step 6: Walk away.</strong> The agent enters the loop. Analyzes what&#39;s failing. Makes one small change to the skill prompt. Tests again. Keeps the change if the score goes up, undoes it if it goes down.</p><p>Then does it again. And again. It keeps going <strong>autonomously</strong> until you stop it or it hits 95%+ three times in a row.</p><p>You can watch the dashboard or walk away entirely. It runs without you. And it saves the improved version as a separate file, so your original skill stays untouched.</p><h2 id="what-happened-to-my-landing-page-skill" tabindex="-1">What happened to my landing page skill <a class="header-anchor" href="#what-happened-to-my-landing-page-skill" aria-label="Permalink to &quot;What happened to my landing page skill&quot;">​</a></h2><p>I ran it on my landing page copy skill. Here&#39;s what came back:</p><p><strong>56% → 92%.</strong> 4 rounds of changes. 3 kept, 1 undone.</p><p>Here&#39;s what the agent actually changed in my skill prompt:</p><ul><li><strong>Added a specific rule</strong> for the most common failure: &quot;Your headline must include a specific number or result. Never use vague promises like &#39;Transform Your Business.&#39;&quot;</li><li><strong>Added a banned buzzwords list:</strong> &quot;NEVER use: revolutionary, cutting-edge, synergy, next-level, game-changing, leverage, unlock, transform.&quot;</li><li><strong>Added a worked example</strong> of a strong landing page section with the pain point opener and CTA highlighted, so the skill could see what good looks like instead of guessing.</li><li><strong>Tried a tighter word count, undid it</strong> because the copy got too thin and the CTA suffered. (The system catches changes that seem like improvements in isolation but hurt the overall output.)</li></ul><p>When it was done, I got:</p><ul><li><strong>The improved skill</strong>, saved separately (the original stays untouched in case you want to revert)</li><li><strong>A results log</strong> showing every round&#39;s score</li><li><strong>A changelog</strong> explaining every change that was tried, why the agent tried it, and whether it helped</li><li><strong>A backup</strong> of my original skill in case I ever want to go back</li></ul><p>That changelog is probably the most valuable piece. It&#39;s a complete record of what works and what doesn&#39;t for that specific skill.</p><p>When smarter models come out down the road, you hand them that changelog and they <strong>pick up right where the last agent left off.</strong></p><h2 id="this-works-on-way-more-than-skills" tabindex="-1">This works on way more than skills <a class="header-anchor" href="#this-works-on-way-more-than-skills" aria-label="Permalink to &quot;This works on way more than skills&quot;">​</a></h2><p>The method works on <strong>anything you can score.</strong></p><ul><li><strong>Website speed:</strong> One person ran this on page load time. Changed one thing, measured the speed, kept or reverted. Went from <strong>1100ms to 67ms</strong> in 67 rounds.</li><li><strong>Cold outreach:</strong> Define your checklist: &quot;Does it mention the prospect&#39;s company? Is it under 75 words? Does it end with a specific question?&quot; Let the agent run 50 variations.</li><li><strong>Newsletter intros:</strong> &quot;Does the opener include a personal detail?&quot; and &quot;Is it free of cliche phrases?&quot; Let the agent tighten your writing on autopilot.</li><li><strong>Any prompt you use repeatedly</strong></li></ul><p>If you can score it, you can autoresearch it.</p><h2 id="go-run-it" tabindex="-1">Go run it <a class="header-anchor" href="#go-run-it" aria-label="Permalink to &quot;Go run it&quot;">​</a></h2><p>Pick your worst-performing skill. Start the autoresearch. Come back to something that actually works.</p><p><strong>Download the skill</strong> <a href="https://www.dropbox.com/scl/fi/57v11vtj9gzqz10ybv7or/autoresearch.zip?rlkey=f0zbieol7beeykn04erun79ot&amp;dl=1" target="_blank" rel="noreferrer">here</a> <strong>(uploaded to dropbox) Or check my github</strong> <a href="https://github.com/olelehmann100kMRR/autoresearch-skill" target="_blank" rel="noreferrer">here</a></p><p>P.S. If you want more AI workflows that help you get more customers, more attention, and more done (without working more hours), I send them to 34k readers every week for free.</p><p>Plus you get a free Claude Cowork masterclass when you join: <a href="http://aisolo.beehiiv.com/subscribe" target="_blank" rel="noreferrer">aisolo.beehiiv.com/subscribe</a></p>',68)])])}const c=t(i,[["render",r]]);export{g as __pageData,c as default};
